mapper.select:
SELECT EXISTS(
    SELECT 1 FROM transactions
    WHERE uuid_recurring_item = #{uuidRecurringItem}
      AND transaction_date = #{date}
      AND deleted_at IS NULL
)

SELECT t.uuid, t.uuid_user, t.uuid_category, t.uuid_recurring_item, t.type, t.amount, t.memo, t.transaction_date,
       t.created_at, t.updated_at, t.deleted_at,
       c.code AS category_code, c.name AS category_name
FROM transactions t
JOIN categories c ON t.uuid_category = c.uuid
WHERE t.uuid_user = #{userId}
  AND t.deleted_at IS NULL
AND t.type = #{request.type}
AND c.code = #{request.categoryCode}

    AND t.transaction_date BETWEEN CONCAT(#{request.period}, '-01-01') AND CONCAT(#{request.period}, '-12-31')


    AND DATE_FORMAT(t.transaction_date, '%Y-%m') = #{request.period}


    AND t.transaction_date = #{request.period}

ORDER BY t.transaction_date

    ASC
    DESC

LIMIT #{request.size} OFFSET #{offset}

SELECT COUNT(*)
FROM transactions t
JOIN categories c ON t.uuid_category = c.uuid
WHERE t.uuid_user = #{userId}
  AND t.deleted_at IS NULL
AND t.type = #{request.type}
AND c.code = #{request.categoryCode}

    AND t.transaction_date BETWEEN CONCAT(#{request.period}, '-01-01') AND CONCAT(#{request.period}, '-12-31')


    AND DATE_FORMAT(t.transaction_date, '%Y-%m') = #{request.period}


    AND t.transaction_date = #{request.period}

SELECT COALESCE(SUM(t.amount), 0)
FROM transactions t
JOIN categories c ON t.uuid_category = c.uuid
WHERE t.uuid_user = #{userId}
  AND t.type = #{type}
  AND t.deleted_at IS NULL

    AND t.transaction_date BETWEEN CONCAT(#{request.period}, '-01-01') AND CONCAT(#{request.period}, '-12-31')


    AND DATE_FORMAT(t.transaction_date, '%Y-%m') = #{request.period}


    AND t.transaction_date = #{request.period}
